  selectors: Record<
    string,
    { dependencies: string[]; dependents: string[]; evaluations: number; dirtyCause: string | null }
  >
  topologicalOrder: string[]
}

export function markAtomicSelector(selector: Selector, meta: SelectorMeta): Selector {
  ;(selector as any)[atomicSelectorMeta] = meta
  return selector
}

function metaFor(selector: Selector): SelectorMeta | undefined {
  return (selector as any)[atomicSelectorMeta]
}

function readPath(state: any, path: string): any {
  const mapIndex = path.indexOf('.map:')
  if (mapIndex !== -1) return readPath(state, path.slice(0, mapIndex))?.get(path.slice(mapIndex + 5))
  const setIndex = path.indexOf('.set:')
  if (setIndex !== -1) return readPath(state, path.slice(0, setIndex))?.has(path.slice(setIndex + 5))
  return path.split('.').reduce((value, key) => (value == null ? undefined : value[key]), state)
}

